fn main() {
    let mut input = String::new();
    std::io::stdin().read_line(&mut input).expect("input: read line failed");
    let number = input.trim().parse::<i32>().expect("number: parse to usize failed");

    let vec = vec![
        hp_judge(0, number),
        hp_judge(1, number),
        hp_judge(2, number),
    ];

    let outcome = great_hp(vec);

    println!("{} {}", outcome.0, outcome.1);



}

fn great_hp(hp_vec: Vec<(i32, i32)>) -> (i32, String) {
    let mut best_hp = (i32::default(), i32::default());

    for item in hp_vec.iter() {
        if item.1 > best_hp.1 {
            best_hp = *item;
        }
    }



    convert(best_hp)
}

fn hp_judge(offset: i32, number: i32) -> (i32, i32) {
    ( offset, grade_estimation(number + offset) )
}

fn grade_estimation(hp: i32) -> i32 {
    let reminder = hp % 4;

    match reminder {
        0 => { 0 },
        1 => { 3 },
        2 => { 1 },
        3 => { 2 },
        _ => { -1 },

    }
}

fn convert(hp: (i32, i32)) -> (i32 ,String) {
    match hp.1 {
        0 => { (hp.0, String::from("D")) },
        3 => { (hp.0, String::from("A")) },
        1 => { (hp.0, String::from("C")) },
        2 => { (hp.0, String::from("B")) },
        _ => { (hp.0, String::from("Err")) },
    }
}
